module RefModule(clk, rst, A, B);input clk, rst;
   input [3:0] A;
   output [3:0] B;

   reg [3:0] A_reg;

     wire _n01 = ~A_reg[0] ^ 1[0];
  wire _c01 = ~A_reg[0] & 1[0];
  wire _n02 = ~A_reg[1] ^ 1[1] ^ _c01;
  wire _c02 = (~A_reg[1] & 1[1]) | (~A_reg[1] & _c01) | (1[1] & _c01);
  wire _n03 = ~A_reg[2] ^ 1[2] ^ _c02;
  wire _c03 = (~A_reg[2] & 1[2]) | (~A_reg[2] & _c02) | (1[2] & _c02);
  wire _n04 = ~A_reg[3] ^ 1[3] ^ _c03;
  wire _c04 = (~A_reg[3] & 1[3]) | (~A_reg[3] & _c03) | (1[3] & _c03);
  assign B = {_n01, _n02, _n03, _n04};

   always @(posedge clk)
      begin
         if (rst)
            A_reg <= 4'b0;
         else
            A_reg <= A;
      end

endmodule
